@Stable
internal fun onStateOf(
    onLoading: ((State.Loading) -> Unit)?,
    onSuccess: ((State.Success) -> Unit)?,
    onError: ((State.Error) -> Unit)?,
): ((State) -> Unit)? {
    return if (onLoading != null || onSuccess != null || onError != null) {
        { state ->
            when (state) {
                is State.Loading -> onLoading?.invoke(state)
                is State.Success -> onSuccess?.invoke(state)
                is State.Error -> onError?.invoke(state)
                is State.Empty -> {}
            }
        }
    } else {
        null
    }
}

private fun BitmapFactory.Options.configureConfig(exifData: ExifData) {
    var config = options.bitmapConfig

    // Disable hardware bitmaps if we need to perform EXIF transformations.
    if (exifData.isFlipped || exifData.isRotated) {
        config = config.toSoftware()
    }

    // Decode the image as RGB_565 as an optimization if allowed.
    if (options.allowRgb565 && config == Bitmap.Config.ARGB_8888 && outMimeType == MIME_TYPE_JPEG) {
        config = Bitmap.Config.RGB_565
    }

    // High color depth images must be decoded as either RGBA_F16 or HARDWARE.
    if (SDK_INT >= 26 && outConfig == Bitmap.Config.RGBA_F16 && config != Bitmap.Config.HARDWARE) {
        config = Bitmap.Config.RGBA_F16
    }

    inPreferredConfig = config
}

internal fun getJpegSizeOrNull(bytes: ByteArray): Pair<Int, Int>? {
    if (bytes.size < 10) return null
    if (int16(bytes[0], bytes[1]) == 0xFFD8u) {
        var offset = 2
        while (offset < bytes.size - 6) {
            val marker = int16(bytes[offset], bytes[offset + 1])
            offset += 2

            if (marker in 0xFFC0u..0xFFCFu && marker != 0xFFC4u && marker != 0xFFC8u && marker != 0xFFCCu) {
                val height = int16(bytes[offset + 3], bytes[offset + 4])
                val width = int16(bytes[offset + 5], bytes[offset + 6])
                return width.toInt() to height.toInt()
            }

            val segmentLength = int16(bytes[offset], bytes[offset + 1])
            offset += segmentLength.toInt()
        }
    }
    return null
}

fun readFrom(source: BufferedSource): NetworkResponse {
    val code = source.readUtf8LineStrict().toInt()
    val requestMillis = source.readUtf8LineStrict().toLong()
    val responseMillis = source.readUtf8LineStrict().toLong()
    val headers = NetworkHeaders.Builder()
    val headersLineCount = source.readUtf8LineStrict().toInt()
    for (i in 0 until headersLineCount) {
        headers.append(source.readUtf8LineStrict())
    }
    return NetworkResponse(
        code = code,
        requestMillis = requestMillis,
        responseMillis = responseMillis,
        headers = headers.build(),
    )
}

internal fun encodeDuration(value: Duration): String = value.toComponents { seconds, nanoseconds ->
    when {
        nanoseconds == 0 -> {
            if (seconds % 60 == 0L) { // minutes
                if (seconds % 3600 == 0L) { // hours
                    if (seconds % 86400 == 0L) { // days
                        "${seconds / 86400} d"
                    } else {
                        "${seconds / 3600} h"
                    }
                } else {
                    "${seconds / 60} m"
                }
            } else {
                "$seconds s"
            }
        }
        nanoseconds % 1_000_000 == 0 -> "${seconds * 1_000 + nanoseconds / 1_000_000} ms"
        nanoseconds % 1_000 == 0 -> "${seconds * 1_000_000 + nanoseconds / 1_000} us"
        else -> "${value.inWholeNanoseconds} ns"
    }
}

@OptIn(ExperimentalSerializationApi::class)
internal inline fun <T, R1 : T, R2 : T> Json.selectMapMode(
    mapDescriptor: SerialDescriptor,
    ifMap: () -> R1,
    ifList: () -> R2
): T {
    val keyDescriptor = mapDescriptor.getElementDescriptor(0).carrierDescriptor(serializersModule)
    val keyKind = keyDescriptor.kind

    return if (keyKind is PrimitiveKind || keyKind == SerialKind.ENUM) {
        ifMap()
    } else if (configuration.allowStructuredMapKeys) {
        ifList()
    } else {
        throw InvalidKeyKindException(keyDescriptor)
    }
}

public fun parse(value: CharSequence): HttpProtocolVersion {
    // Fast path: check common versions first to avoid allocation
    if (value == "HTTP/1.1") return HTTP_1_1
    if (value == "HTTP/1.0") return HTTP_1_0
    if (value == "HTTP/2.0") return HTTP_2_0
    if (value == "HTTP/3.0") return HTTP_3_0

    // Slow path: parse unknown versions (format: protocol/major.minor)
    val (protocol, major, minor) = value.split("/", ".").also {
        check(it.size == 3) {
            "Failed to parse HttpProtocolVersion. Expected format: protocol/major.minor, but actual: $value"
        }
    }

    return fromValue(protocol, major.toInt(), minor.toInt())
}

internal actual fun CharsetEncoder.encodeImpl(
    input: CharSequence,
    fromIndex: Int,
    toIndex: Int,
    dst: Sink
): Int {
    require(fromIndex <= toIndex)
    if (charset == Charsets.ISO_8859_1) {
        return encodeISO88591(input, fromIndex, toIndex, dst)
    }

    require(charset === Charsets.UTF_8) { "Only UTF-8 encoding is supported in JS" }

    val encoder = TextEncoder() // Only UTF-8 is supported so we know that at most 6 bytes per character is used
    val result = encoder.encode(input.substring(fromIndex, toIndex))
    dst.write(result.unsafeCast<ByteArray>())
    return result.length
}

private suspend fun ApplicationCall.redirectAuthenticateOAuth2(
    authenticateUrl: String,
    callbackRedirectUrl: String,
    clientId: String,
    state: String,
    scopes: List<String>,
    parameters: List<Pair<String, String>>,
    interceptor: URLBuilder.(ApplicationRequest) -> Unit
) {
    val url = URLBuilder()
    url.takeFrom(authenticateUrl)
    url.parameters.apply {
        append(OAuth2RequestParameters.ClientId, clientId)
        append(OAuth2RequestParameters.RedirectUri, callbackRedirectUrl)
        if (scopes.isNotEmpty()) {
            append(OAuth2RequestParameters.Scope, scopes.joinToString(" "))
        }
        append(OAuth2RequestParameters.State, state)
        append(OAuth2RequestParameters.ResponseType, "code")
        parameters.forEach { (k, v) -> append(k, v) }
    }
    url.interceptor(this.request)

    return respondRedirect(url.buildString())
}
